(81, 1, '2013-08-18 15:48:20', '2013-08-18 15:48:20', '[ux_banner height=\"360px\" bg=\"20\" bg_overlay=\"rgba(0, 0, 0, 0.16)\" bg_pos=\"56% 97%\" parallax=\"2\"]\n\n[text_box width=\"63\" width__sm=\"60%\" text_depth=\"1\"]\n\n<h3 class=\"uppercase\"><strong>Categories Element</strong></h3>\n<p class=\"lead\">Create beautiful overview of your Shop categories. There is almost unlimited variations, but here are some examples.</p>\n\n[/text_box]\n\n[/ux_banner]\n[row]\n\n[col]\n\n[title style=\"center\" text=\"Simple\"]\n\n[ux_product_categories style=\"normal\"]\n\n[title style=\"center\" text=\"Badge style\"]\n\n[ux_product_categories]\n\n[title style=\"center\" text=\"Overlay Style\"]\n\n[ux_product_categories style=\"overlay\" slider_nav_style=\"simple\" slider_nav_position=\"outside\" image_overlay=\"rgba(0, 0, 0, 0.19)\" image_hover=\"overlay-remove-50\" image_hover_alt=\"zoom\"]\n\n[title style=\"center\" text=\"Grid style\"]\n\n[ux_product_categories style=\"overlay\" type=\"grid\" grid=\"3\" columns=\"3\" animate=\"fadeInLeft\" number=\"4\" orderby=\"name\" image_size=\"large\" image_overlay=\"rgba(38, 38, 38, 0.16)\" text_pos=\"middle\" text_size=\"large\"]\n\n[title style=\"center\" text=\"Circle Style\"]\n\n[ux_product_categories style=\"overlay\" slider_nav_style=\"simple\" slider_nav_position=\"outside\" image_height=\"100%\" image_radius=\"100\" image_overlay=\"rgba(0, 0, 0, 0.19)\" image_hover=\"overlay-remove-50\" image_hover_alt=\"zoom\" text_pos=\"middle\" text_size=\"large\" text_hover=\"bounce\"]\n\n\n[/col]\n\n[/row]\n[section bg_color=\"rgb(51, 51, 51)\" dark=\"true\"]\n\n[title style=\"center\" text=\"Be creative! Mix and match settings\"]\n\n[ux_product_categories style=\"overlay\" type=\"grid\" grid=\"13\" col_spacing=\"small\" columns=\"3\" depth_hover=\"5\" animate=\"fadeInLeft\" number=\"5\" orderby=\"name\" image_size=\"large\" image_overlay=\"rgba(38, 38, 38, 0.16)\" image_hover=\"color\" image_hover_alt=\"zoom-long\" text_pos=\"middle\" text_size=\"large\"]\n\n\n[/section]', 'Product Categories', '', 'publish', 'closed', 'closed', '', 'product-categories', '', '', '2026-05-06 08:14:06', '2026-05-06 08:14:06', '', 100, 'http://localhost:8888/test/?page_id=654', 22, 'page', '', 0),
(82, 1, '2013-08-18 15:41:31', '2013-08-18 15:41:31', '[ux_banner height=\"451px\" bg=\"20\" bg_overlay=\"rgba(0, 0, 0, 0.45)\"]\r\n\r\n[text_box width=\"66\" parallax=\"-4\"]\r\n\r\n<h2 class=\"uppercase\"><strong>Product Element</strong></h2>\r\n<p class=\"lead\">List products anywhere in a beautiful style. Choose between Slider, Rows, Grid and Masonry Style. Select products from a custom category or sort by sales, featured items or latest. You can also select custom products.</p>\r\n\r\n[/text_box]\r\n\r\n[/ux_banner]\r\n[title style=\"bold-center\" text=\"Simple Sale Slider\"]\r\n\r\n[ux_products orderby=\"sales\" show=\"onsale\"]\r\n\r\n[title style=\"bold-center\" text=\"Featured Products Slider\" icon=\"icon-star\"]\r\n\r\n[ux_products  show=\"featured\"]\r\n\r\n[title style=\"bold-center\" text=\"Best Selling Products\" icon=\"icon-heart\"]\r\n\r\n[ux_products orderby=\"sales\"]\r\n\r\n[title style=\"bold-center\" text=\"Lookbook style\"]\r\n\r\n[ux_products style=\"shade\" slider_nav_style=\"circle\" col_spacing=\"normal\" depth=\"1\" depth_hover=\"5\" cat=\"tops\" image_height=\"200%\" image_size=\"medium\" image_hover=\"overlay-add\" image_hover_alt=\"zoom-long\" text_size=\"large\" text_hover=\"hover-slide\"]\r\n\r\n[title style=\"bold-center\" text=\"Lookbook style 2\"]\r\n\r\n[ux_products style=\"overlay\" slider_nav_style=\"circle\" width=\"full-width\" col_spacing=\"collapse\" columns=\"6\" cat=\"80\" orderby=\"rand\" image_height=\"200%\" image_size=\"medium\" image_overlay=\"rgba(0, 0, 0, 0.58)\" image_hover=\"overlay-add\" image_hover_alt=\"zoom-long\" text_pos=\"middle\" text_size=\"large\" text_hover=\"zoom-in\"]\r\n\r\n[title style=\"bold-center\" text=\"Grid Style\" margin_top=\"16px\"]\r\n\r\n[ux_products style=\"shade\" type=\"grid\" grid_height=\"650px\" products=\"4\" orderby=\"sales\" show=\"featured\" image_overlay=\"rgba(0, 0, 0, 0.19)\" image_hover=\"zoom\" image_hover_alt=\"glow\" text_align=\"left\" text_size=\"large\"]\r\n\r\n[title style=\"bold-center\" text=\"Masonery Style\"]\r\n\r\n[ux_products type=\"masonry\" depth=\"1\" depth_hover=\"5\" text_align=\"left\"]\r\n\r\n[title style=\"bold-center\" text=\"Mix and match styles\"]\r\n\r\n[ux_products style=\"overlay\" image_height=\"169%\" image_size=\"medium\" image_overlay=\"rgba(0, 0, 0, 0.67)\" image_hover=\"color\" image_hover_alt=\"overlay-remove-50\" text_size=\"large\"]', 'Products', '', 'publish', 'closed', 'closed', '', 'products', '', '', '2026-05-06 08:14:06', '2026-05-06 08:14:06', '', 100, 'http://localhost:8888/test/?page_id=650', 23, 'page', '', 0);
