(101, 1, '2013-08-06 20:13:19', '2013-08-06 20:13:19', '<!-- wp:flatsome/uxbuilder -->\n[ux_slider]\n\n[ux_banner height=\"600px\" bg=\"338\" bg_overlay=\"rgba(0, 0, 0, 0.02)\" bg_pos=\"58% 63%\"]\n\n[text_box width=\"70\" width__sm=\"100\" animate=\"flipInY\" position_x=\"50\" position_y=\"50\"]\n\n<h3 class=\"alt-font\">It has Finally started...</h3>\n[divider margin=\"3px\"]\n\n<h1 class=\"h-large uppercase\"><span style=\"font-size: 160%;\"><strong>HUGE SALE</strong></span></h1>\n<h1 class=\"uppercase\"><span style=\"font-size: 100%;\">UP TO <strong>70% OFF</strong></span></h1>\n\n[divider]\n\n\n[/text_box]\n\n[/ux_banner]\n[ux_banner height=\"600px\" bg=\"336\" bg_overlay=\"rgba(0, 0, 0, 0.03)\" bg_pos=\"72% 6%\"]\n\n[text_box text_color=\"dark\" width=\"40\" width__sm=\"85\" animate=\"fadeInLeft\" position_x=\"5\" position_x__sm=\"50\" position_y=\"50\"]\n\n<h3 class=\"alt-font\">Sportswear Collection</h3>\n<h2 class=\"uppercase\" data-animate=\"fadeInLeft\" data-animated=\"true\"><strong>Active Style</strong></h2>\n<h3><strong>From $19</strong></h3>\n\n[divider]\n\n[button text=\"Shop now\" style=\"outline\"]\n\n\n[/text_box]\n\n[/ux_banner]\n[ux_banner height=\"600px\" bg=\"337\" bg_overlay=\"rgba(0, 0, 0, 0.05)\" bg_pos=\"67% 70%\"]\n\n[text_box width=\"40\" width__sm=\"100\" animate=\"fadeInLeft\" position_x=\"90\" position_x__sm=\"50\" position_y=\"50\" position_y__sm=\"50\"]\n\n<h3 class=\"alt-font\">Workout Essentials</h3>\n<h2 class=\"uppercase\" data-animate=\"fadeInLeft\" data-animated=\"true\"><strong>Build Your</strong></h2>\n<h2 class=\"uppercase\"><strong>Home Gym</strong></h2>\n<p class=\"lead\">Everything you need for stronger, smarter, and more effective training sessions.</p>\n\n[button text=\"Browse Products\"]\n\n\n[/text_box]\n\n[/ux_banner]\n\n[/ux_slider]\n[row]\n\n[col span=\"4\" span__sm=\"12\"]\n\n[ux_banner height=\"160px\" bg=\"20\" bg_pos=\"55% 11%\" hover=\"zoom-fade\" link=\"blog\"]\n\n[text_box position_x=\"50\" position_y=\"50\"]\n\n<h2><strong><span class=\"uppercase\">Our Blog</span></strong></h2>\n[divider]\n\n\n[/text_box]\n\n[/ux_banner]\n\n[/col]\n[col span=\"4\" span__sm=\"12\"]\n\n[ux_banner height=\"160px\" bg=\"20\" hover=\"zoom-fade\" link=\"http://localhost:8888/test/blog/\"]\n\n[text_box position_x=\"50\" position_y=\"50\"]\n\n<h2><strong><span class=\"uppercase\">Join our<br />\n<span style=\"font-size: 85%;\">competition</span></span></strong></h2>\n[divider]\n\n\n[/text_box]\n\n[/ux_banner]\n\n[/col]\n[col span=\"4\" span__sm=\"12\"]\n\n[ux_banner height=\"160px\" bg=\"20\" bg_pos=\"71% 0%\" hover=\"zoom-fade\" link=\"about-us\"]\n\n[text_box position_x=\"50\" position_y=\"50\"]\n\n<h2><strong><span class=\"uppercase\">ABOUT US</span></strong></h2>\n[divider]\n\n\n[/text_box]\n\n[/ux_banner]\n\n[/col]\n\n[/row]\n[title style=\"center\" text=\"weekly featured products\"]\n\n[ux_products products=\"14\" show=\"featured\"]\n\n[title style=\"center\" text=\"Best Selling Products\" size=\"undefined\"]\n\n[ux_products orderby=\"sales\"]\n\n[title style=\"center\" text=\"Browse our categories\"]\n\n[ux_product_categories number=\"20\"]\n\n[gap height=\"40px\"]\n\n[row col_style=\"divided\"]\n\n[col span=\"4\"]\n\n[featured_box img=\"19\" img_width=\"46\" pos=\"center\" title=\"Free Shipping on all orders\" margin=\"0px 0px 0px 0px\" icon_border=\"2\" icon_color=\"rgb(182, 182, 182)\"]\n\n<p>Offer nationwide delivery, with careful packaging and delivery directly to your door. The shop will contact you to confirm your order before shipping.</p>\n\n\n[/featured_box]\n\n[/col]\n[col span=\"4\"]\n\n[featured_box img=\"19\" img_width=\"46\" pos=\"center\" title=\"CUSTOMER SUPPORT\" margin=\"0px 0px 0px 0px\" icon_border=\"2\" icon_color=\"rgb(182, 182, 182)\"]\n\n<p> Shop always ready to advise you on the right size, style, and product to suit your training needs via hotline, Zalo, or fanpage.\n </p>\n\n\n[/featured_box]\n\n[/col]\n[col span=\"4\"]\n\n[featured_box img=\"19\" img_width=\"46\" pos=\"center\" title=\"EASY PAYMENT\" margin=\"0px 0px 0px 0px\" icon_border=\"2\" icon_color=\"rgb(182, 182, 182)\"]\n\n<p>We support cash on delivery or manual bank transfer. Order details are clearly confirmed before delivery.</p>\n\n\n[/featured_box]\n\n[/col]\n\n[/row]\n[gap height=\"40px\"]\n\n[title style=\"center\" text=\"Latest News\" size=\"undefined\"]\n\n[blog_posts columns__sm=\"1\" animate=\"fadeInLeft\" posts=\"4\" image_height=\"70%\"]\n\n\n<!-- /wp:flatsome/uxbuilder -->', 'Classic Shop', '', 'publish', 'closed', 'closed', '', 'classic-shop', '', '', '2026-05-06 11:44:44', '2026-05-06 11:44:44', '', 73, 'http://localhost:8888/test/?page_id=17', 1, 'page', '', 0),
