(162, 1, '2016-09-03 16:24:28', '2016-09-03 16:24:28', '[row style=\"small\" h_align=\"center\" class=\"flatsome-demos\"]\r\n\r\n[col span=\"9\" span__sm=\"12\" align=\"center\"]\r\n<h2>Flatsome Theme Demos</h2>\r\n<p class=\"lead\">Flatsome includes many pre-made homepages and settings you can add with a single click. These are just examples. You can mix and match headers, pages, colors and fonts using the Theme Option Panel.</p>\r\n[/col]\r\n\r\n[/row]\r\n\r\n[title style=\"center\" text=\"Shop Demos\"]\r\n\r\n[ux_pages style=\"default\" parent=\"3021\" col_spacing=\"small\" columns=\"3\" depth=\"1\" depth_hover=\"4\" image_size=\"medium\" image_overlay=\"rgba(0, 0, 0, 0)\" text_align=\"center\" text_bg=\"rgba(255, 255, 255, 0.63)\" text_padding=\"5px 5px 5px 5px\"]\r\n\r\n[title style=\"center\" text=\"Business Demos\"]\r\n\r\n[ux_pages style=\"default\" parent=\"3025\" col_spacing=\"small\" columns=\"3\" depth=\"1\" depth_hover=\"4\" image_size=\"medium\" image_overlay=\"rgba(0, 0, 0, 0)\" text_align=\"center\" text_bg=\"rgba(255, 255, 255, 0.76)\" text_padding=\"5px 5px 5px 5px\"]', 'Demos', '', 'publish', 'closed', 'closed', '', 'demos', '', '', '2016-09-03 16:24:28', '2016-09-03 16:24:28', '', 0, 'http://flatsome.dev/?post_type=blocks&amp;p=9439', 0, 'blocks', '', 0),
