(366, 1, '2026-05-06 15:05:17', '2026-05-06 15:05:17', '<!-- wp:flatsome/uxbuilder -->\n[ux_banner height=\"507px\" bg=\"20\" bg_overlay=\"rgba(0, 0, 0, 0.49)\" parallax=\"3\"]\n\n[text_box width=\"79\" position_x=\"50\" position_y=\"80\"]\n\n<h1 class=\"lead\">About Us</h1>\n<p class=\"lead\">We are a small sportswear store created for students and young people who love an active lifestyle. We understand that students need products that are comfortable, stylish, useful, and affordable, so our store focuses on sportswear, sneakers, accessories, and workout equipment that fit both daily life and student budgets.</p>\n\n[/text_box]\n\n[/ux_banner]\n[row]\n\n[col span__sm=\"12\"]\n\n<p class=\"lead text-center\">Whether you are going to class, training at the gym, running, playing football with friends, or simply choosing a sporty outfit for the day, we want to help you feel confident, comfortable, and ready to move. Our goal is to bring simple designs, practical products, and fair prices to everyone who wants to stay active every day.</p>\n[divider align=\"center\"]\n\n\n[/col]\n[col span=\"3\" span__sm=\"12\"]\n\n[team_member img=\"19\" name=\"Troy Gray\" title=\"CEO / Founder\" facebook=\"#\" twitter=\"#\" email=\"#\" pinterest=\"#\" linkedin=\"#\" image_height=\"100%\" image_width=\"80\" image_radius=\"100\"]\n\n<p>Lorem ipsum dolor sit amet, consectetuer adipiscing elit, sed diam nonummy.</p>\n\n[/team_member]\n\n[/col]\n[col span=\"3\" span__sm=\"12\"]\n\n[team_member img=\"19\" name=\"Richy Lace\" title=\"Marketing Director\" facebook=\"#\" twitter=\"#\" email=\"#\" pinterest=\"#\" linkedin=\"#\" image_height=\"100%\" image_width=\"80\" image_radius=\"100\"]\n\n<p>Lorem ipsum dolor sit amet, consectetuer adipiscing elit, sed diam nonummy.</p>\n\n[/team_member]\n\n[/col]\n[col span=\"3\" span__sm=\"12\"]\n\n[team_member img=\"19\" name=\"Jane Gray\" title=\"Public Relations\" facebook=\"#\" twitter=\"#\" email=\"#\" pinterest=\"#\" linkedin=\"#\" image_height=\"100%\" image_width=\"80\" image_radius=\"100\"]\n\n<p>Lorem ipsum dolor sit amet, consectetuer adipiscing elit, sed diam nonummy.</p>\n\n[/team_member]\n\n[/col]\n[col span=\"3\" span__sm=\"12\"]\n\n[team_member img=\"19\" name=\"July Wood\" title=\"Customer Support\" facebook=\"#\" twitter=\"#\" email=\"#\" pinterest=\"#\" linkedin=\"#\" image_height=\"100%\" image_width=\"80\" image_radius=\"100\"]\n\n<p>Lorem ipsum dolor sit amet, consectetuer adipiscing elit, sed diam nonummy.</p>\n\n[/team_member]\n\n[/col]\n\n[/row]\n\n<!-- /wp:flatsome/uxbuilder -->', 'About', '', 'inherit', 'closed', 'closed', '', '93-revision-v1', '', '', '2026-05-06 15:05:17', '2026-05-06 15:05:17', '', 93, 'http://localhost/sportwearweb/?p=366', 0, 'revision', '', 0),
